#!node

const { readFileSync, writeFileSync, mkdirSync, existsSync } = require("fs");
const path = require("path");

const PORT = Number(process.argv[2]);

const mkdirin = (dir) => {
  existsSync(dir) || mkdirSync(dir);
}

const router = readFileSync(path.resolve(__dirname, "../src/router.js"), "utf-8")
  .replace("$port", isNaN(PORT) ? 80 : PORT);
const snippet = readFileSync(path.resolve(__dirname, "../src/snippet.js"));

mkdirin("node_modules");
mkdirin("node_modules/@router");
mkdirin("views");
mkdirin("routes");

writeFileSync("node_modules/@router/package.json", JSON.stringify({ main: "router.js" }));
writeFileSync("node_modules/@router/router.js", router);
if(!existsSync("index.js")) writeFileSync("index.js", snippet);